pub fn finish_size_prefixed_krf_buffer<'a, 'b, A: ::flatbuffers::Allocator + 'a>(fbb: &'b mut ::flatbuffers::FlatBufferBuilder<'a, A>, root: ::flatbuffers::WIPOffset<KRF<'a>>) {
  fbb.finish_size_prefixed(root, Some(KRF_IDENTIFIER));
}
